package main

import (
	"fmt"
	"io"
	"net/http"
	"os"
)

func uploadFile(w http.ResponseWriter, r *http.Request) {
	// Maximum upload of 10 MB files
	r.ParseMultipartForm(10 << 20)

	// Get handler for filename, size and headers
	file, handler, err := r.FormFile("myFile")
	if err != nil {
		fmt.Println("Error Retrieving the File")
		return
	}
	defer file.Close()

	// Create a new file in public directory
	dst, err := os.Create("./public/" + handler.Filename)
	if err != nil {
		fmt.Println(err)
		return
	}
	defer dst.Close()

	// Copy the uploaded file to the filesystem at specified destination
	_, err = io.Copy(dst, file)
	if err != nil {
		fmt.Println(err)
		return
	}

	// Return the filename to user
	w.Write([]byte("./public/" + handler.Filename))
}

func main() {
	http.HandleFunc("/upload", uploadFile)
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
		fmt.Println(err)
	}
}